import os
import sys
import json
import numpy as np
from collections import deque
from cogniplan_env import ExplorationEnv


def round_coords(coords, precision=1):
    return (round(coords[0], precision), round(coords[1], precision))


def select_waypoint(obs, alpha=1.2, use_adaptive=True):
    """Select the best neighbor using adaptive cost-aware utility scoring."""
    nodes = obs['nodes']
    neighbors = obs['neighbors']
    robot_pos = round_coords(obs['robot_pos'])
    frontiers = obs['frontiers']
    explored_rate = obs['explored_rate']

    if not neighbors:
        return None

    # Adaptive alpha based on exploration progress
    cur_alpha = alpha
    if use_adaptive:
        if explored_rate < 0.7:
            cur_alpha = alpha
        elif explored_rate < 0.9:
            cur_alpha = alpha + 0.3
        else:
            cur_alpha = alpha + 0.8

    # Build graph
    graph = {}
    node_by_coords = {}
    for node in nodes:
        coords = round_coords(node['coords'])
        node_by_coords[coords] = node
        graph[coords] = [round_coords(n) for n in node['neighbors']]

    # Find start node (closest to robot)
    start = robot_pos
    if start not in graph:
        min_dist = float('inf')
        for coords in graph:
            d = (coords[0] - robot_pos[0]) ** 2 + (coords[1] - robot_pos[1]) ** 2
            if d < min_dist:
                min_dist = d
                start = coords

    # BFS distances from start
    distances = {start: 0}
    queue = deque([start])
    while queue:
        current = queue.popleft()
        for neighbor in graph.get(current, []):
            if neighbor not in distances:
                distances[neighbor] = distances[current] + 1
                queue.append(neighbor)

    # Score nodes with utility > 0 (skip visited nodes)
    best_score = -1
    best_target = None

    for node in nodes:
        if node['utility'] <= 0:
            continue
        if node['visited']:
            continue
        coords = round_coords(node['coords'])
        dist = distances.get(coords, float('inf'))
        if dist == float('inf') or dist == 0:
            continue

        score = node['utility'] / (dist ** cur_alpha)
        if score > best_score:
            best_score = score
            best_target = coords

    # Frontier-guided fallback when no utility nodes found
    if best_target is None:
        if frontiers:
            # Find nearest frontier that has a reachable node nearby
            best_frontier = None
            best_fdist = float('inf')
            for f in frontiers:
                d = (f[0] - robot_pos[0]) ** 2 + (f[1] - robot_pos[1]) ** 2
                if d < best_fdist:
                    best_fdist = d
                    best_frontier = f

            # Find neighbor closest to frontier
            best_neighbor = None
            best_ndist = float('inf')
            for n in neighbors:
                d = (n[0] - best_frontier[0]) ** 2 + (n[1] - best_frontier[1]) ** 2
                if d < best_ndist:
                    best_ndist = d
                    best_neighbor = n
            if best_neighbor is not None:
                return best_neighbor

        # Last resort: pick neighbor with highest utility
        best_utility = -1
        best_neighbor = None
        for n in neighbors:
            coords = round_coords(n)
            node = node_by_coords.get(coords)
            if node and node['utility'] > best_utility:
                best_utility = node['utility']
                best_neighbor = n
        if best_neighbor is None:
            best_neighbor = neighbors[0]
        return best_neighbor

    # BFS path to best target
    if start == best_target:
        best_n = None
        best_nu = -1
        for n in neighbors:
            nc = round_coords(n)
            nd = node_by_coords.get(nc)
            if nd and nd['utility'] > best_nu:
                best_nu = nd['utility']
                best_n = n
        return best_n if best_n else neighbors[0]

    visited_bfs = {start}
    bfs_queue = deque([(start, [start])])
    path = None
    found = False
    while bfs_queue and not found:
        current, current_path = bfs_queue.popleft()
        for neighbor in graph.get(current, []):
            if neighbor == best_target:
                path = current_path + [neighbor]
                found = True
                break
            if neighbor not in visited_bfs:
                visited_bfs.add(neighbor)
                bfs_queue.append((neighbor, current_path + [neighbor]))

    if path and len(path) > 1:
        next_node = path[1]
        # Choose neighbor closest to next path node, with utility tie-breaking
        best_dist = float('inf')
        best_util = -1
        best_n = None
        for n in neighbors:
            nr = round_coords(n)
            d = (nr[0] - next_node[0]) ** 2 + (nr[1] - next_node[1]) ** 2
            nd = node_by_coords.get(nr)
            u = nd['utility'] if nd else 0
            if d < best_dist or (d == best_dist and u > best_util):
                best_dist = d
                best_util = u
                best_n = n
        return best_n if best_n else neighbors[0]
    else:
        # Fallback: closest neighbor to best target
        best_dist = float('inf')
        best_n = None
        for n in neighbors:
            d = (n[0] - best_target[0]) ** 2 + (n[1] - best_target[1]) ** 2
            if d < best_dist:
                best_dist = d
                best_n = n
        return best_n if best_n else neighbors[0]


def run_episode(env, alpha=1.2, use_adaptive=True):
    obs = env.reset()
    for step in range(128):
        target = select_waypoint(obs, alpha=alpha, use_adaptive=use_adaptive)
        if target is None:
            break
        obs, info = env.step(target)
        if info['done']:
            break
    return env.get_metrics()


def main():
    import argparse
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    args = parser.parse_args()

    # Load config from checkpoint
    config_path = os.path.join(args.checkpoint, 'config.json')
    if os.path.exists(config_path):
        with open(config_path) as f:
            config = json.load(f)
    else:
        config = {'alpha': 1.2, 'method': 'adaptive_cost_aware_utility'}

    alpha = config.get('alpha', 1.2)

    # Load eval config
    eval_config_path = os.path.join(args.data_path, 'eval_config.json')
    with open(eval_config_path) as f:
        eval_config = json.load(f)

    # Find all eval maps
    maps_dir = os.path.join(args.data_path, 'maps_eval')
    per_episode = []
    type_results = {'room': [], 'tunnel': [], 'outdoor': []}

    for env_type in ['room', 'tunnel', 'outdoor']:
        type_dir = os.path.join(maps_dir, env_type)
        if not os.path.isdir(type_dir):
            continue
        map_files = sorted([f for f in os.listdir(type_dir) if f.endswith('.png')])

        for map_file in map_files:
            map_path = os.path.join(type_dir, map_file)
            env = ExplorationEnv(map_path=map_path)
            metrics = run_episode(env, alpha=alpha)

            rel_path = f"{env_type}/{map_file}"
            episode = {
                'map_path': rel_path,
                'env_type': env_type,
                'success': int(metrics['success']),
                'travel_distance': metrics['travel_distance'],
                'explored_rate': metrics['explored_rate']
            }
            per_episode.append(episode)
            type_results[env_type].append(metrics)

    # Compute aggregate metrics
    total = len(per_episode)
    explored_rate = np.mean([e['explored_rate'] for e in per_episode])
    success_rate = np.mean([e['success'] for e in per_episode])
    succ_dists = [e['travel_distance'] for e in per_episode if e['success']]
    travel_distance = np.mean(succ_dists) if succ_dists else 0.0

    per_type = {}
    for env_type, metrics_list in type_results.items():
        if metrics_list:
            per_type[env_type] = {
                'explored_rate': float(np.mean([m['explored_rate'] for m in metrics_list])),
                'travel_distance': float(np.mean([m['travel_distance'] for m in metrics_list if m['success']])) if any(m['success'] for m in metrics_list) else 0.0,
                'success_rate': float(np.mean([m['success'] for m in metrics_list]))
            }

    result = {
        'explored_rate': float(explored_rate),
        'travel_distance': float(travel_distance),
        'success_rate': float(success_rate),
        'per_episode': per_episode,
        'per_type': per_type,
        'total_episodes': total
    }

    with open(args.output, 'w') as f:
        json.dump(result, f, indent=2)

    print(f"Evaluated {total} maps: success={success_rate:.3f}, explored={explored_rate:.4f}, dist={travel_distance:.1f}")


if __name__ == '__main__':
    main()
